CREATE TABLE "royalty_statements" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"import_file_id" uuid NOT NULL REFERENCES "import_files"("id"),"source_connector" text NOT NULL,"currency" text NOT NULL,"periods" text[] NOT NULL DEFAULT '{}',"total_royalties" numeric(20,6) NOT NULL,"line_count" numeric(12,0) NOT NULL,"hash" text NOT NULL);
CREATE UNIQUE INDEX "royalty_statements_tenant_hash_uq" ON "royalty_statements"("tenant_id","hash");
CREATE TABLE "royalty_lines" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"royalty_statement_id" uuid NOT NULL REFERENCES "royalty_statements"("id"),"business_key" text NOT NULL,"classification" text NOT NULL,"status" text NOT NULL,"period" text NOT NULL,"title" text,"isbn_or_asin" text NOT NULL,"store" text,"units_sold" numeric(12,0),"units_returned" numeric(12,0),"units_net" numeric(12,0),"amount" numeric(20,6) NOT NULL,"currency" text NOT NULL,"average_unit_price" numeric(20,6),"production_cost" numeric(20,6),"kenp_pages" numeric(12,0),"source_sheet" text NOT NULL);
CREATE UNIQUE INDEX "royalty_lines_tenant_key_uq" ON "royalty_lines"("tenant_id","business_key");
CREATE INDEX "royalty_lines_statement_idx" ON "royalty_lines"("royalty_statement_id");
